import{c as a,Q as s,j as i,m as e}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"Android 的世界观:Linux + AOSP + ART + APK 心智","description":"","frontmatter":{},"headers":[],"relativePath":"androidPlatformLearning/01-Android的世界观.md","filePath":"androidPlatformLearning/01-Android的世界观.md","lastUpdated":1779789238000}'),o={name:"androidPlatformLearning/01-Android的世界观.md"};function p(t,n,l,r,d,c){return s(),i("div",null,[...n[0]||(n[0]=[e(`<h1 id="android-的世界观-linux-aosp-art-apk-心智" tabindex="-1">Android 的世界观:Linux + AOSP + ART + APK 心智 <a class="header-anchor" href="#android-的世界观-linux-aosp-art-apk-心智" aria-label="Permalink to &quot;Android 的世界观:Linux + AOSP + ART + APK 心智&quot;">​</a></h1><blockquote><p>一句话:<strong>Android 不是&quot;一个 App 平台&quot;,是一个</strong>完整的操作系统——Linux 内核之上盖了一层 Java/Kotlin 运行时和系统服务,你写的 App 是这套系统里的一个<strong>沙箱进程</strong>。理解这件事,从 Activity 生命周期到 Binder IPC 才有正确的心智锚点。</p></blockquote><hr><h2 id="一、android-不是-windows-也不是-ios" tabindex="-1">一、Android 不是 Windows 也不是 iOS <a class="header-anchor" href="#一、android-不是-windows-也不是-ios" aria-label="Permalink to &quot;一、Android 不是 Windows 也不是 iOS&quot;">​</a></h2><p>很多人对 Android 的初始印象是&quot;运行 App 的手机系统&quot;,这个印象会让你<strong>看不懂为什么 Activity 生命周期这么复杂、为什么 Service 后台被杀、为什么 Binder 到处都是</strong>。</p><table tabindex="0"><thead><tr><th>维度</th><th>Windows</th><th>iOS</th><th>Android</th></tr></thead><tbody><tr><td>内核</td><td>NT</td><td>XNU(Mach + BSD)</td><td><strong>Linux</strong></td></tr><tr><td>应用容器</td><td>EXE / UWP / 沙箱</td><td>App + sandbox(seatbelt)</td><td><strong>每个 App 一个 Linux UID 沙箱进程</strong></td></tr><tr><td>主要 IPC</td><td>COM / RPC</td><td>XPC / Mach port</td><td><strong>Binder</strong>(独有)</td></tr><tr><td>UI 主线程模型</td><td>Win32 消息循环</td><td>RunLoop</td><td><strong>Looper + MessageQueue</strong></td></tr><tr><td>应用包格式</td><td>EXE / MSIX</td><td>IPA(签名容器)</td><td><strong>APK / AAB</strong>(zip + DEX + 资源)</td></tr><tr><td>字节码 / 原生</td><td>x86 / ARM 原生</td><td>LLVM Bitcode → ARM</td><td><strong>DEX 字节码,ART 跑</strong></td></tr></tbody></table><p><strong>心智差别最大的是 IPC 与进程模型</strong>:</p><ul><li>Windows / iOS 的 App 也是进程,但跨进程通信复杂,所以&quot;系统调用&quot;接近 system call</li><li>Android 把&quot;调用系统服务&quot;包装成&quot;调用一个本地对象的方法&quot;,底层走 Binder 自动跨到 system_server 进程——你写 <code>notificationManager.notify(...)</code> 这一行,实际跨进程到了另一个进程</li></ul><p>这件事是 Android 整个 SDK 设计的基础。后面 04 篇 Binder 会展开。</p><hr><h2 id="二、android-的五层结构" tabindex="-1">二、Android 的五层结构 <a class="header-anchor" href="#二、android-的五层结构" aria-label="Permalink to &quot;二、Android 的五层结构&quot;">​</a></h2><p>从下到上:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Android Applications                                │  ← 你的 App / 系统 App(Phone / Settings / Camera)</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  Java/Kotlin Framework API                           │  ← android.* / androidx.*(Activity / View / ...)</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  System Services(SystemServer 进程)                 │  ← AMS / WMS / PMS / InputManagerService / ...</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  Native Libraries + Android Runtime(ART)            │  ← libc / libbinder / libui / SurfaceFlinger / 你的 DEX</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  Linux Kernel + Android-specific drivers             │  ← Binder driver / ashmem / wakelock / Low Memory Killer</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>每一层的关键认识</strong>:</p><ol><li><p><strong>Linux 内核</strong>——是标准 Linux,但加了 Android 独有的 Binder driver、ashmem(匿名共享内存)、低内存杀手(LMK)、wakelock。<strong>Android 的进程隔离用的就是 Linux 的 UID/sandbox 机制</strong>。</p></li><li><p><strong>Native 层 + ART</strong>——<code>libc</code> 兼容 POSIX 但是 Bionic libc 不是 glibc;<code>SurfaceFlinger</code> 是渲染合成的最终落点;<strong>ART</strong> 是 Android 自己的 JVM,跑 DEX 字节码(不是 Java class)。</p></li><li><p><strong>系统服务</strong>——一个进程叫 <code>system_server</code>,里面跑了<strong>几十个系统服务</strong>:AMS(Activity Manager)/ WMS(Window Manager)/ PMS(Package Manager)/ Notification / Power / Location / ConnectivityManager。<strong>你 App 进程的所有&quot;看似本地&quot;的 SDK 调用,大量都是通过 Binder 跨到这个 system_server</strong>。</p></li><li><p><strong>Framework API</strong>——<code>android.app.Activity</code> / <code>android.view.View</code> 这些类的实现散落在 Framework 源码里,本质是&quot;调用系统服务的 Java 客户端&quot;。</p></li><li><p><strong>App 层</strong>——你写的代码,在自己进程跑。</p></li></ol><p>读完本系列,你应当能看着上面这张图说出&quot;我点击按钮调 <code>startActivity(intent)</code>,这一行代码经过哪几层、跨了几次进程&quot;——这就是 Android 平台心智。</p><hr><h2 id="三、android-是-linux-但又不是普通-linux" tabindex="-1">三、Android 是 Linux,但又不是普通 Linux <a class="header-anchor" href="#三、android-是-linux-但又不是普通-linux" aria-label="Permalink to &quot;三、Android 是 Linux,但又不是普通 Linux&quot;">​</a></h2><p>Android 在 Linux 之上重新设计了&quot;应用模型&quot;——传统 Linux 应用通过 <code>fork</code> + <code>exec</code> 启动,Android <strong>不是</strong>:</p><p><strong>典型 Linux</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>shell$ ./myapp           # fork + exec</span></span>
<span class="line"><span>       myapp 进程从零启动,加载 ELF,运行 main()</span></span></code></pre></div><p><strong>Android</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开机 → init → 启动 Zygote 进程(预加载 ART + 大量系统类)</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>       Zygote 持续 listening</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>       用户点 App 图标 → AMS 通过 socket 让 Zygote fork 一个子进程</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>       fork 出来的子进程已经预加载了所有系统类(Copy-on-Write 共享)</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>       AMS 让这个新进程 setUid 到目标 App 的 UID</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>       新进程开始跑你的 Application.onCreate() / Activity.onCreate()</span></span></code></pre></div><p><strong>关键设计</strong>:<strong>Zygote 是所有 App 进程的&quot;妈妈&quot;</strong>。一旦 Zygote 启动并预加载了 ART runtime 和系统类,后续 fork 出来的 App 进程都共享这些预加载好的内存(Copy-on-Write)——<strong>这是 Android 启动一个 App 比启动一个普通 Linux 应用快得多的根本原因</strong>。</p><p>这件事影响后面很多设计:</p><ul><li><strong>每个 App 进程都跑一份 ART</strong>,而不是共享一个 ART 实例(Java 服务器的模型)</li><li><strong>进程死了所有状态丢光</strong>(没有 daemon 持久化),所以 ViewModel 才需要 SavedStateHandle</li><li><strong>进程可以随时被杀</strong>(内存压力),所以 Activity 生命周期才设计成可以&quot;任意点死/任意点活&quot;</li></ul><p>03 篇会展开 Zygote / 进程模型。</p><hr><h2 id="四、android-上没有-java-但有-dex-art" tabindex="-1">四、Android 上没有 Java,但有 DEX + ART <a class="header-anchor" href="#四、android-上没有-java-但有-dex-art" aria-label="Permalink to &quot;四、Android 上没有 Java,但有 DEX + ART&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你写的 Kotlin / Java 源码</span></span>
<span class="line"><span>     ↓ (kotlinc / javac)</span></span>
<span class="line"><span>JVM 字节码(.class 文件)</span></span>
<span class="line"><span>     ↓ (d8 / dexer)</span></span>
<span class="line"><span>DEX 字节码(.dex 文件,Dalvik EXecutable)</span></span>
<span class="line"><span>     ↓</span></span>
<span class="line"><span>打进 APK</span></span>
<span class="line"><span>     ↓</span></span>
<span class="line"><span>安装时:dex2oat 工具把 DEX 编译为机器码(.oat 文件,AOT)</span></span>
<span class="line"><span>     ↓</span></span>
<span class="line"><span>运行时:ART 加载 OAT,直接执行机器码;不命中的部分用解释器 + JIT</span></span></code></pre></div><p><strong>关键认识</strong>:</p><ol><li><p><strong>APK 里没有 .class 文件,只有 .dex</strong>——DEX 是寄存器模型(JVM 是栈模型),专门为移动端优化。一个 DEX 文件可以容纳多个类,体积比一堆 .class 小。</p></li><li><p><strong>JVM 字节码与 DEX 字节码是两种东西</strong>——Android 不直接跑 JVM 字节码,所有 JVM 字节码都要转换。这是 d8/dexer 干的事。</p></li><li><p><strong>ART 替代了 Dalvik</strong>(Android 5.0 起)——Dalvik 是早期 Android 的虚拟机,纯 JIT;ART 是新一代,有 AOT(安装时编译)+ JIT(运行时编译热路径)+ Baseline Profile(02 / 21 篇)。</p></li><li><p><strong>Android 也有 Native 代码(.so)</strong>——通过 JNI 调用。但应用层 99% 是 DEX,只有图像处理 / 游戏引擎 / 加密用 .so。</p></li></ol><p>06 篇会展开 ART 的 GC / AOT / JIT。</p><hr><h2 id="五、apk-android-app-的物理载体" tabindex="-1">五、APK:Android App 的物理载体 <a class="header-anchor" href="#五、apk-android-app-的物理载体" aria-label="Permalink to &quot;五、APK:Android App 的物理载体&quot;">​</a></h2><p>APK(Android Package)是个 zip 文件,改后缀解压能看到:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NotedX.apk</span></span>
<span class="line"><span>├── AndroidManifest.xml      ← 应用清单(声明组件、权限、Activity、Service 等)</span></span>
<span class="line"><span>├── classes.dex              ← 主 DEX(可能有 classes2.dex / classes3.dex,叫 multidex)</span></span>
<span class="line"><span>├── resources.arsc           ← 编译后的资源索引(string / dimension / color / layout 引用)</span></span>
<span class="line"><span>├── res/                     ← 资源文件(布局 XML、图片、字符串)</span></span>
<span class="line"><span>├── assets/                  ← 原样保留的资源(不经编译)</span></span>
<span class="line"><span>├── lib/</span></span>
<span class="line"><span>│   ├── arm64-v8a/*.so       ← native 库(按 ABI 拆分)</span></span>
<span class="line"><span>│   └── armeabi-v7a/*.so</span></span>
<span class="line"><span>├── META-INF/</span></span>
<span class="line"><span>│   ├── MANIFEST.MF          ← 文件哈希清单</span></span>
<span class="line"><span>│   ├── CERT.SF              ← 签名信息</span></span>
<span class="line"><span>│   └── CERT.RSA             ← 签名公钥与证书</span></span>
<span class="line"><span>└── kotlin/                  ← Kotlin metadata</span></span></code></pre></div><p><strong>安装过程</strong>:</p><ol><li>PackageManager(PMS,系统服务)接到 APK</li><li>解析 AndroidManifest,把组件信息(Activity/Service/Receiver)注册到系统</li><li>给 App <strong>分配一个唯一 UID</strong>(从 10000 开始)</li><li>dex2oat 把 DEX 编译为机器码,放在 <code>/data/dalvik-cache/</code></li><li>APK 复制到 <code>/data/app/&lt;package_name&gt;/base.apk</code></li><li>App 的&quot;数据目录&quot; <code>/data/data/&lt;package_name&gt;/</code> 创建(权限 700,只有自己 UID 可读)</li></ol><p><strong>App 安装后的物理位置</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/data/app/com.notedx-1/base.apk           # APK 本体</span></span>
<span class="line"><span>/data/data/com.notedx/files/              # Context.filesDir</span></span>
<span class="line"><span>/data/data/com.notedx/databases/          # Room / SQLite 数据库</span></span>
<span class="line"><span>/data/data/com.notedx/shared_prefs/       # SharedPreferences</span></span>
<span class="line"><span>/data/data/com.notedx/cache/              # Context.cacheDir</span></span></code></pre></div><p>02 篇会展开 APK / 安装 / 签名。</p><hr><h2 id="六、aosp-android-是开源的" tabindex="-1">六、AOSP:Android 是开源的 <a class="header-anchor" href="#六、aosp-android-是开源的" aria-label="Permalink to &quot;六、AOSP:Android 是开源的&quot;">​</a></h2><p><strong>AOSP</strong>(Android Open Source Project)是 Google 维护的 Android 开源代码库。AOSP 包含:</p><ul><li>Linux 内核(Android 分支)</li><li>Bionic libc</li><li>ART</li><li>所有系统服务(<code>frameworks/base/services/</code> 下面)</li><li>默认系统 App(Phone / Settings / Camera / Launcher)</li><li>SDK 构建工具</li></ul><p><strong>手机厂商基于 AOSP 改</strong>——三星 OneUI、小米 HyperOS、华为 EMUI / HarmonyOS 都基于 AOSP 改造。Google Pixel 是最接近原生 AOSP 的手机。</p><p><strong>国内厂商通常会改的部分</strong>:</p><ul><li>通知中心 / 桌面 Launcher / 主题</li><li>推送通道(替代 GMS 推送)</li><li>应用权限管理(常常比 AOSP 更严)</li><li>后台限制(更激进的电池优化)</li><li>内置应用商店 / 系统服务</li></ul><p><strong>为什么这对应用开发者重要</strong>?——<strong>同一份 APK 在不同厂商手机上行为可能不同</strong>。AOSP 上能跑的代码,vivo 可能因为后台限制不工作;Pixel 上的网络栈是标准 OkHttp,华为可能拦截某些域名;Pixel 上的 NotificationChannel 行为是标准的,小米可能默认折叠你的通知。这些是 Android 工程的现实复杂度。</p><p>读 AOSP 源码:<a href="https://cs.android.com/" target="_blank" rel="noreferrer">https://cs.android.com/</a> 是 Google 提供的代码搜索。本系列后面引用 AOSP 源码都从这里。</p><hr><h2 id="七、android-版本号-api-level-代号" tabindex="-1">七、Android 版本号 / API Level / 代号 <a class="header-anchor" href="#七、android-版本号-api-level-代号" aria-label="Permalink to &quot;七、Android 版本号 / API Level / 代号&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Android 4.4 KitKat        API 19   (2013)</span></span>
<span class="line"><span>Android 5.0 Lollipop      API 21   (2014)  ART 取代 Dalvik</span></span>
<span class="line"><span>Android 6.0 Marshmallow   API 23   (2015)  运行时权限</span></span>
<span class="line"><span>Android 7.0 Nougat        API 24   (2016)</span></span>
<span class="line"><span>Android 8.0 Oreo          API 26   (2017)  NotificationChannel、后台限制</span></span>
<span class="line"><span>Android 9.0 Pie           API 28   (2018)</span></span>
<span class="line"><span>Android 10.0              API 29   (2019)  分区存储</span></span>
<span class="line"><span>Android 11.0              API 30   (2020)</span></span>
<span class="line"><span>Android 12.0              API 31   (2021)  Material You / 启动屏 API</span></span>
<span class="line"><span>Android 13.0              API 33   (2022)  通知权限、按 App 设置语言</span></span>
<span class="line"><span>Android 14.0              API 34   (2023)  前台服务 type 强制</span></span>
<span class="line"><span>Android 15.0              API 35   (2024)  edge-to-edge 强制</span></span>
<span class="line"><span>Android 16.0              API 36   (2025)</span></span></code></pre></div><p><strong>重要变更节点</strong>:</p><ul><li><strong>API 21</strong>——ART 取代 Dalvik(性能提升关键)</li><li><strong>API 23</strong>——危险权限改为运行时申请(以前是安装时全给)</li><li><strong>API 26</strong>——后台启动 Service 严格限制(<code>startService</code> 在 App 不可见时直接抛异常,推动 WorkManager 诞生)</li><li><strong>API 28</strong>——加密强制(<code>cleartextTraffic</code> 默认 false,HTTPS 才能用)</li><li><strong>API 29</strong>——分区存储(<code>READ_EXTERNAL_STORAGE</code> 大部分场景不再有用)</li><li><strong>API 33</strong>——通知权限运行时申请、Per-App 语言</li><li><strong>API 35</strong>——edge-to-edge 强制(必须主动处理 system bar 内边距)</li></ul><p>每个版本都有&quot;行为变更&quot;——你 App 的 <code>targetSdk</code> 决定它<strong>按哪个版本行为运行</strong>。后续 22 章会反复回到这些节点。</p><hr><h2 id="八、本系列的整体地图" tabindex="-1">八、本系列的整体地图 <a class="header-anchor" href="#八、本系列的整体地图" aria-label="Permalink to &quot;八、本系列的整体地图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01     世界观(这篇)</span></span>
<span class="line"><span>02-06  Android OS 平台:APK / 沙箱 / Binder / 系统服务 / ART</span></span>
<span class="line"><span>       这是&quot;Android 是什么&quot;的根基,任何应用开发问题都能在这里找答案</span></span>
<span class="line"><span></span></span>
<span class="line"><span>07-11  四大组件:Activity / Fragment / Service / Receiver / Provider</span></span>
<span class="line"><span>       Android 应用与系统对话的契约 API,Compose 时代仍然每个都要懂</span></span>
<span class="line"><span></span></span>
<span class="line"><span>12-13  主线程心智:Handler / Looper / ANR / 异步演化</span></span>
<span class="line"><span>       为什么 Android 主线程这么&quot;娇贵&quot;,AsyncTask 怎么死的</span></span>
<span class="line"><span></span></span>
<span class="line"><span>14-17  View 系统:绘制三阶段 / XML / 自定义 View / 资源</span></span>
<span class="line"><span>       Compose 之下,View 仍然是物理实现。读老代码 / 自定义 View 必修</span></span>
<span class="line"><span></span></span>
<span class="line"><span>18-19  数据持久化(旧路径):SharedPreferences / SQLite / ContentResolver</span></span>
<span class="line"><span>       Room / DataStore 的&quot;祖宗&quot;,且老开源项目仍在大量使用</span></span>
<span class="line"><span></span></span>
<span class="line"><span>20-22  安全与排障:权限 / 签名 / Sandbox / 内存泄漏 / 性能工具</span></span>
<span class="line"><span>       从能写代码 → 能修线上 Bug 的鸿沟,本节填平</span></span></code></pre></div><p><strong>优先级</strong>:</p><ul><li>想懂 Compose 之下到底发生了什么 → 01-06 必看</li><li>维护老项目 → 07-19 全看</li><li>想会排查线上 Bug → 12-13 + 20-22</li></ul><hr><h2 id="九、踩坑提醒-总览版" tabindex="-1">九、踩坑提醒(总览版) <a class="header-anchor" href="#九、踩坑提醒-总览版" aria-label="Permalink to &quot;九、踩坑提醒(总览版)&quot;">​</a></h2><ol><li><strong>把&quot;Android 应用&quot;和&quot;Android 系统&quot;当一回事</strong>——你的 App 是 Android 系统里的一个<strong>沙箱进程</strong>,大部分 Android 行为是系统决定的,不是你 App 决定的(后台限制 / 进程被杀 / Activity 生命周期)。</li><li><strong>以为 Java 在 Android 上和服务器一样</strong>——Android 上是 DEX + ART,不是 .class + HotSpot。GC 策略、内存模型、AOT 时机全部不同。</li><li><strong>把所有问题归因于&quot;Android 慢&quot;</strong>——99% 慢都是你 App 慢,不是 Android 慢。Profile 之前别下结论。</li><li><strong>认为 Activity 是&quot;屏幕&quot;</strong>——Activity 是<strong>一个与系统协商生命周期的契约</strong>,不是 UI。它可以没有 UI(<code>Theme.NoDisplay</code>),也可以有多个 UI(Fragment / Compose 子树)。</li><li><strong>以为 Service 是&quot;后台线程&quot;</strong>——Service 是&quot;在主线程跑、生命周期跟着 AMS&quot;的组件,跟&quot;后台线程&quot;没关系。Service 里依然不能阻塞主线程。</li><li><strong>以为 manifest 里声明权限就有权限</strong>——危险权限必须运行时弹窗申请(API 23+),manifest 声明只是&quot;允许我去申请&quot;。</li><li><strong>以为 IPC 慢可以无视</strong>——Android 上你天天调系统服务,每次都跨进程。设计不当(频繁调 <code>WindowManager</code> / <code>PackageManager</code>)会显著拖慢启动。</li><li><strong>以为 Linux 知识不重要</strong>——Android 是 Linux,<code>/proc/&lt;pid&gt;/</code> 能看到你 App 的内存、文件描述符、线程;<code>adb shell</code> 就是个 Linux shell。Linux 基础每天都用。</li><li><strong>以为系统服务都是&quot;普通 Java 类&quot;</strong>——它们是 Binder 服务,可能在 system_server 跑,可能在其他独立进程(Camera / Audio)跑。你调的是&quot;代理对象&quot;。</li><li><strong>以为&quot;现代 Android 不用懂这些&quot;</strong>——Compose / Kotlin / Hilt 是上层封装,<strong>下面的 Activity / Looper / Binder / View 一个都没消失</strong>。封装漏了你就得自己懂。</li></ol><hr><p>下一篇 <code>02-APK 解剖.md</code>,把 APK 完全拆开:Manifest 语法、DEX 文件格式、resources.arsc 怎么编译、签名方案 v1/v2/v3/v4 各自意义、安装时操作系统做了什么。读完你能从一份 APK 解出&quot;这个 App 声明了什么、签名属于谁、要哪些权限&quot;。</p>`,67)])])}const u=a(o,[["render",p]]);export{g as __pageData,u as default};
